import { useEffect } from "react";
import { Outlet, Link } from "react-router-dom";
import { createRoot } from "react-dom/client";
import {Helmet} from "react-helmet";
import './home.scss';
import $ from 'jquery';

const Home = () => {
    
    useEffect(()=>{
        document.body.className = "homeBody";
        if(window.getComputedStyle(document.querySelector(".homeBody")).paddingTop !== "22px"){
            $("h1").after("<div id='svgContainer'></div>");
            createRoot(document.getElementById("svgContainer")).render(getSVG());
        }
        let loadingEl = $("#loading");
        loadingEl.fadeOut();
        return ()=>{
            document.body.classList.remove("homebody");
            loadingEl.css("display","block");
        };
    },[])

    function getSVG(){
        return (
            <svg height="30px" width="100%" viewBox="0 0 100 100"  preserveAspectRatio="none">
                <path d="M0,0 L0,50 Q25,100 50,50 75,0 100,50 L 100,0" vectorEffect="non-scaling-stroke" strokeWidth="3" stroke="#913213" fill="#913213" />
                <path d="M0,50 Q25,100 50,50 75,0 100,50 " vectorEffect="non-scaling-stroke" strokeWidth="3" stroke="#692112" fill="none"/>
            </svg>
        );
    }

    return (
        <div id="home">
            <Helmet>
                <title>Uzair's Study Notes</title>
                <meta name="viewport" content="width=device-width, initial-scale=1.0"/>
            </Helmet>
            <h1>My Study Notes</h1>
            <h2>Language Learning</h2>
            <Link to={{pathname:"language_learning/semantics"}}>Semantics</Link>
            <Link to={{pathname:"language_learning/korean"}}>Korean</Link>
            <Link to={{pathname:"language_learning/madinah_arabic_book_3"}}>Madinah Arabic Book 3</Link>
            <Link to={{pathname:"language_learning/french"}}>French</Link>
            <h2>Computer Security</h2>
            <Link to={{pathname:"computer_security/introduction_to_computer_security"}}>Introduction To Computer Security</Link>
            <Link to={{pathname:"computer_security/cryptography"}}>Cryptography</Link>
            <h2>AI Related Stuff</h2>
            <Link to={{pathname:"AI_related_stuff/data_mining"}}>Data Mining</Link>
            <Link to={{pathname:"AI_related_stuff/data_analytics_with_R"}}>Data Analytics With R</Link>
            <footer><Link to={{pathname:"guide"}}>Website Guide</Link><Link to={{pathname:"contact"}}>Contact Us</Link></footer>
            <Outlet />
        </div>
    )
};

export default Home;